#include <stdio.h>
#include <stdlib.h>
#include "am1_core.h"
#include "am1_observer.h"
static unsigned long long parse_ull(const char *s){ char *end=0; unsigned long long v=strtoull(s,&end,10); if(!s || !*s || (end && *end)) return 0ULL; return v; }
int main(int argc, char **argv){ unsigned long long steps,sample_every,i; const char *prefix; char obs_path[1024], state_path[1024]; FILE *obs_fp,*state_fp; am1_term *root; am1_observation o; if(argc!=4){ fprintf(stderr,"usage: %s <steps> <sample_every> <out_prefix>\n", argv[0]); return 1; } steps=parse_ull(argv[1]); sample_every=parse_ull(argv[2]); prefix=argv[3]; if(steps==0ULL || sample_every==0ULL){ fprintf(stderr,"steps and sample_every must be positive integers\n"); return 1; } snprintf(obs_path,sizeof(obs_path),"%s_observables.csv",prefix); snprintf(state_path,sizeof(state_path),"%s_state.txt",prefix); obs_fp=fopen(obs_path,"w"); if(!obs_fp){ perror("fopen observables"); return 1; } fprintf(obs_fp,"step,total_terms,pole_0_terms,pole_1_terms,origin_terms,unresolved_terms,mirror_terms,self_attempt_terms,reexpression_terms,articulation_terms\n"); root=am1_initial_state(); am1_observe(root,&o); fprintf(obs_fp,"0,%zu,%zu,%zu,%zu,%zu,%zu,%zu,%zu,%zu\n", o.total_terms,o.pole_0_terms,o.pole_1_terms,o.origin_terms,o.unresolved_terms,o.mirror_terms,o.self_attempt_terms,o.reexpression_terms,o.articulation_terms); for(i=1ULL;i<=steps;++i){ am1_step(&root); if(i % sample_every == 0ULL){ am1_observe(root,&o); fprintf(obs_fp,"%llu,%zu,%zu,%zu,%zu,%zu,%zu,%zu,%zu,%zu\n", i,o.total_terms,o.pole_0_terms,o.pole_1_terms,o.origin_terms,o.unresolved_terms,o.mirror_terms,o.self_attempt_terms,o.reexpression_terms,o.articulation_terms); } } fclose(obs_fp); state_fp=fopen(state_path,"w"); if(!state_fp){ perror("fopen state"); am1_free(root); return 1; } am1_print(state_fp,root); fputc('\n',state_fp); fclose(state_fp); am1_free(root); return 0; }
